};

function generateSignature(key) {
  const sig = SIGNATURES[key] || SIGNATURES['default'];
  return `
<div style="border-top:1px solid #ccc;margin-top:20px;padding-top:20px;font-family:Arial,sans-serif;font-size:13px;color:#333">
  <strong>${sig.name}</strong><br/>
  ${sig.title} | ${sig.company}<br/>
  <a href="tel:${sig.phone}" style="color:#0066cc;text-decoration:none">📞 ${sig.phone}</a><br/>
  <a href="mailto:${sig.email}" style="color:#0066cc;text-decoration:none">✉️ ${sig.email}</a><br/>
  <a href="https://${sig.website}" style="color:#0066cc;text-decoration:none">🌐 ${sig.website}</a><br/>
  <a href="${sig.bookingUrl}" style="color:#54B6B4;text-decoration:none;font-weight:bold">Prendre un rendez-vous</a>
</div>`;
}

// Get data from the flow
const item = $input.first().json;
const firstname = item.contact_firstname || '';
const companyName = item.company_name || '';
